dashboard.definition:
{
  "title": "Platform Posture",
  "description": "Simple synthetic posture summary with no real data ingestion.",
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "-24h@h",
            "latest": "now"
          }
        }
      }
    }
  },
  "visualizations": {
    "viz_bar": {
      "type": "splunk.bar",
      "dataSources": {
        "primary": "ds_bar"
      },
      "title": "Synthetic Capacity Trend",
      "options": {
        "legendDisplay": "off"
      }
    },
    "viz_table": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_table"
      },
      "title": "Service Status"
    }
  },
  "dataSources": {
    "ds_bar": {
      "type": "ds.search",
      "name": "Synthetic capacity",
      "options": {
        "query": "| makeresults count=5 | streamstats count as slot | eval category=\"window_\".slot, value=slot*12 | table category value"
      }
    },
    "ds_table": {
      "type": "ds.search",
      "name": "Synthetic services",
      "options": {
        "query": "| makeresults | eval service=\"argocd\", status=\"healthy\" | append [| makeresults | eval service=\"ingress\", status=\"healthy\"] | append [| makeresults | eval service=\"splunk\", status=\"experimental\"] | table service status"
      }
    }
  },
  "layout": {
    "type": "absolute",
    "options": {
      "display": "auto-scale",
      "width": 1440,
      "height": 900
    },
    "structure": [
      {
        "item": "viz_bar",
        "type": "block",
        "position": {
          "x": 80,
          "y": 80,
          "w": 620,
          "h": 320
        }
      },
      {
        "item": "viz_table",
        "type": "block",
        "position": {
          "x": 80,
          "y": 450,
          "w": 620,
          "h": 250
        }
      }
    ]
  }
}
